var preloaderDiv=document.getElementById("preloader");function hidePreloader(){preloaderDiv.className="displaynone"}function showPreloader(){preloaderDiv.className=""}function shiftUpPreloader(){turnOffPreloaderDotsAnimation(),$(preloaderDiv).stop().animate({bottom:"100%"},1e3,()=>{hidePreloader()})}function turnOffPreloaderDotsAnimation(){preloaderDotsDiv.className="preloader-dots-static"}preloaderDiv.className="transparent";var preloaderDotsDiv=document.getElementById("preloader-dots");showPreloader();